<span class="line"><span style="color:#F8F8F2;">xhr.</span><span style="color:#A6E22E;">overrideMimeType</span><span style="color:#F8F8F2;">(</span><span style="color:#E6DB74;">&#39;text/xml&#39;</span><span style="color:#F8F8F2;">);</span></span>
